<?php
namespace App\Modules\Hr\Performance\Actions;
use App\Modules\Hr\Core\Services\HrAuditService; use App\Modules\Hr\Core\Services\TenantContext; use App\Modules\Hr\Performance\Enums\PerformanceEvaluationStatus; use App\Modules\Hr\Performance\Models\HrPerformanceEvaluation;
class CalibratePerformanceEvaluationAction { public function __construct(private HrAuditService $audit,private \App\Modules\Hr\Performance\Services\PerformanceResultService $results){} public function execute(HrPerformanceEvaluation $evaluation,float $score,string $note):HrPerformanceEvaluation{abort_unless(auth()->user()?->hasHrPermission('hr.performance.calibrate'),403);abort_unless($evaluation->legal_entity_id===app(TenantContext::class)->getId(),404);$evaluation->loadMissing('cycle');abort_unless($evaluation->cycle->status===\App\Modules\Hr\Performance\Enums\PerformanceCycleStatus::Calibration,422,'Döngü kalibrasyon aşamasında değil.');abort_unless($evaluation->status===PerformanceEvaluationStatus::Submitted,422,'Yalnızca gönderilmiş değerlendirme kalibre edilebilir.');abort_if($score<0||$score>100||blank($note),422,'Kalibrasyon puanı ve gerekçesi zorunludur.');$evaluation->update(['status'=>PerformanceEvaluationStatus::Calibrated,'calibrated_score'=>round($score,2),'calibration_note'=>trim($note),'calibrated_by'=>auth()->id(),'calibrated_at'=>now()]);$this->results->recalculate($evaluation->legal_entity_id,$evaluation->cycle_id,$evaluation->employee_id);$this->audit->log('performance_evaluation_calibrated',$evaluation,['overall_score'=>$evaluation->overall_score],['calibrated_score'=>$score,'calibration_note'=>$note]);return $evaluation->fresh();} }
